var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"콜록 콜록- 성공한 건가?","JPN":"ゲホ、ゲホ……成功したのか？","ENG":"*Cough!* *Cough!* Did it work?","TWN":"咳咳，咳咳- 成功降落嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"으윽… 충격으로 머리를 부딪힌 것 같은데.","JPN":"ううっ……衝撃で頭をぶつけたみたいだな。","ENG":"Urgh... I think I bumped my head.","TWN":"呃…剛剛衝擊太大，害我好像撞到頭咧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"어이, 네놈이 만들었다는 탈출장치. 제대로 작동한 거 맞아?","JPN":"おい、てめえが作ったという脱出装置。ちゃんと作動したのか？","ENG":"Hey, that escape pod that you made. Are you sure it worked?","TWN":"喂，這是你們做的逃生裝置，確定有正常運作吧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"그 끈질긴 우주경찰 놈들에게서 도망칠 방법이 있다더니, 날 대체 어디로 데려온 것이냐?","JPN":"あのしつこい宇宙警察の奴らから逃げる方法があると言っていたが、いったいどこへ連れて来たのだ？","ENG":"You told me that there is a way to run away from those tedious space cops, but where have you brought me to?","TWN":"說什麼有辦法可以躲避那些難纏的宇宙警察，結果到底把我帶到什麼地方來啦？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"나도 몰라. 급하게 가동하느라 좌표를 설정할 시간도 없었으니까.","JPN":"俺にもわからないな。急いで起動させたせいで、座標を設定する時間すらなかった。","ENG":"I don’t know. I was rushing so much, I didn’t have time to set the coordinates.","TWN":"我也不知道，剛剛啟動的時候情況很緊急，根本來不及設定座標。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"킁킁, 어디서 탄내가 나는데?","JPN":"クンクン、どこかで焦げた匂いがするが？","ENG":"*Sniff, sniff* Something’s burning.","TWN":"嗅嗅，哪來的味道？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"아, 망할놈의 워프 장치가 또 고장 났군.","JPN":"あーあ、ポンコツワープ装置がまた壊れやがった。","ENG":"Oh, the damn warp machine is broken again.","TWN":"可惡，這個爛東西的控制裝置又壞了。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"뭣?! 그럼 돌아갈 방법이 없다는 거야?","JPN":"はあ！？　となると、戻る方法がないのか？","ENG":"What?! Does that mean that there’s no way of going back?","TWN":"什麼？！我們沒辦法回去的意思嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"고작 한 번 사용한 걸로 망가지다니. 하여간 고철을 좋아하는 것 치고 제대로 완성할 줄 아는 것이 없구나.","JPN":"一度使ったくらいで壊れるとは。まったく、くず鉄好きの割にまともなものは作れんのだな。","ENG":"Breaking down after a single use? Should've known better from a junk collector like you.","TWN":"才用一次就壞掉，說什麼喜歡廢鐵，結果根本一點辦法也沒有。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"아아, 뭐가 이렇게 잔말들이 많아? 싫으면 거기 남아서 정의집행이나 당하시던가.","JPN":"ああ、ごちゃごちゃうるさい。イヤならそこに残って警察につかまったらどうだ？","ENG":"Stop complaining! You could've just stayed and let justice be served upon your pathetic selves.","TWN":"喂喂，廢話那麼多，有意見的話你們怎麼不留在那直接被原地逮捕？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"그러고보니 그 강소영이란 우주경찰 녀석, 널 보면서 만년 묵은 뱀으로 술을 담그면 기가 막히겠다고 했었지 아마?","JPN":"そういえばあのマエカワ・ナツミという宇宙警察、お前を見ながら一万年生きた蛇で作った酒はうまそうだとか言ってたよな？","ENG":"Come to think of it, that space cop named Kang Soyoung... She said something about brewing liquor with a snake that’s old as time itself, no?","TWN":"話說回來，那個叫姜素英的宇宙警察應該是說要把你抓去泡蛇酒喝掉吧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"아직도 생각만 하면 소름이 끼치는군.","JPN":"いまだに思い出すだけでぞっとする。","ENG":"I still get goosebumps when I think about it.","TWN":"想到我就頭皮發麻。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"난 인간의 마음을 읽을 줄 알지만… 그 눈빛은 진심이었어.","JPN":"我は人間の心を読むことができるが……あの目は本気であった。","ENG":"I can read human minds... And she wasn’t joking when she said it.","TWN":"雖然我會讀人類的心思…但她的眼神，是認真的。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"하아, 배고프구만. 난 밥이나 먹으러 가련다.","JPN":"はあ、腹減ったなあ。アタシは飯でも食いに行くぞ。","ENG":"*Sigh...* I’m hungry. Might as well get something to eat.","TWN":"唉唷，肚子好餓，我要去找東西吃。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"무식한 녀석이 팔자걱정도 없구나. 여기가 어딘 줄 알고 함부로 발길을 옮기는 것이냐?","JPN":"愚か者は先の心配もないのだな。ここがどこかもわからないのにむやみに動くつもりなのか？","ENG":"Look who’s making herself at home already. You don’t even know the area here!","TWN":"頭腦簡單的傢伙果然是天不怕地不怕。你以為這裡是哪裡，竟然敢輕易移動腳步？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"우리가 살던 동네랑 별 차이 없어 보이는데, 아무 식당이나 들어가면 되는 거 아닌가?","JPN":"アタシたちが住んでいた街とあんま変わんないようだけど、適当にどこかの店に入ればいいんじゃないか？","ENG":"It doesn’t look that different from our side of town. Just get inside any restaurant.","TWN":"這裡看起來跟我們住的地方附近差不多啊，不是隨便找間餐廳進去就好嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"어리석군. 언제 어디서 우주경찰 녀석들이 다시 나타날지도 모르는데…","JPN":"愚かな。いつどこから宇宙警察がまた現れるやも知れぬというのに……","ENG":"Fool. Those space cops could barge in any second...","TWN":"蠢東西，宇宙警察不知道什麼時候又會冒出來…"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};